#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, S;
        scanf("%d %d", &N, &S);
        int **dp = (int **)malloc((N + 1) * sizeof(int *));
        for (int i = 0; i <= N; i++) {
            dp[i] = (int *)malloc((S + 1) * sizeof(int));
        }
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j <= S; j++) {
                dp[i][j] = 0;
            }
        }
        dp[0][0] = 1;
        for (int i = 1; i <= N; i++) {
            int A, B, C;
            scanf("%d %d %d", &A, &B, &C);
            for (int j = 0; j <= S; j++) {
                for (int k = 0; k <= j / A; k++) {
                    if (k * B < k * C) {
                        dp[i][j] = (dp[i][j] + dp[i - 1][j - k * A]) % MOD;
                    }
                }
            }
        }
        int ans = 0;
        for (int i = 0; i <= S; i++) {
            ans = (ans + dp[N][i]) % MOD;
        }
        printf("%d\n", ans);
        for (int i = 0; i <= N; i++) {
            free(dp[i]);
        }
        free(dp);
    }
    return 0;
}

