                    for (int k = 0; k <= j / A; k++) {
                        if (k * B < k * C) {
                            dp[i][j] = (dp[i][j] + dp[i - 1][j - k * A]) % 1000000007;
                        }
                    }
                }
            }
            int ans = 0;
